    39→static bool _profile_count_as_native(const Object *p_base_obj, const StringName &p_methodname) {
    40→	if (!p_base_obj) {
    41→		return false;
    42→	}
    43→	StringName cname = p_base_obj->get_class_name();
    44→	if ((p_methodname == "new" && cname == "GDScript") || p_methodname == "call") {
    45→		return false;
    46→	}
    47→	return ClassDB::class_exists(cname) && ClassDB::has_method(cname, p_methodname, false);
    48→}
