   137→String GDScriptFunction::_get_call_error(const Callable::CallError &p_err, const String &p_where, const Variant **argptrs) const {
   138→	String err_text;
   139→
   140→	if (p_err.error == Callable::CallError::CALL_ERROR_INVALID_ARGUMENT) {
   141→		int errorarg = p_err.argument;
   142→		ERR_FAIL_COND_V_MSG(errorarg < 0 || argptrs[errorarg] == nullptr, "GDScript bug (please report): Invalid CallError argument index or null pointer.", "Invalid CallError argument index or null pointer.");
   143→		// Handle the Object to Object case separately as we don't have further class details.
   144→#ifdef DEBUG_ENABLED
   145→		if (p_err.expected == Variant::OBJECT && argptrs[errorarg]->get_type() == p_err.expected) {
   146→			err_text = "Invalid type in " + p_where + ". The Object-derived class of argument " + itos(errorarg + 1) + " (" + _get_var_type(argptrs[errorarg]) + ") is not a subclass of the expected argument class.";
   147→		} else if (p_err.expected == Variant::ARRAY && argptrs[errorarg]->get_type() == p_err.expected) {
   148→			err_text = "Invalid type in " + p_where + ". The array of argument " + itos(errorarg + 1) + " (" + _get_var_type(argptrs[errorarg]) + ") does not have the same element type as the expected typed array argument.";
   149→		} else
   150→#endif // DEBUG_ENABLED
   151→		{
   152→			err_text = "Invalid type in " + p_where + ". Cannot convert argument " + itos(errorarg + 1) + " from " + Variant::get_type_name(argptrs[errorarg]->get_type()) + " to " + Variant::get_type_name(Variant::Type(p_err.expected)) + ".";
   153→		}
   154→	} else if (p_err.error == Callable::CallError::CALL_ERROR_TOO_MANY_ARGUMENTS) {
   155→		err_text = "Invalid call to " + p_where + ". Expected " + itos(p_err.expected) + " arguments.";
   156→	} else if (p_err.error == Callable::CallError::CALL_ERROR_TOO_FEW_ARGUMENTS) {
   157→		err_text = "Invalid call to " + p_where + ". Expected " + itos(p_err.expected) + " arguments.";
   158→	} else if (p_err.error == Callable::CallError::CALL_ERROR_INVALID_METHOD) {
   159→		err_text = "Invalid call. Nonexistent " + p_where + ".";
   160→	} else if (p_err.error == Callable::CallError::CALL_ERROR_INSTANCE_IS_NULL) {
   161→		err_text = "Attempt to call " + p_where + " on a null instance.";
   162→	} else if (p_err.error == Callable::CallError::CALL_ERROR_METHOD_NOT_CONST) {
   163→		err_text = "Attempt to call " + p_where + " on a const instance.";
   164→	} else {
   165→		err_text = "Bug, call error: #" + itos(p_err.error);
   166→	}
   167→
   168→	return err_text;
   169→}
